animations.cssText:
@keyframes shopify-rotator { 
  0% { transform: rotate(0deg); }
  100% { transform: rotate(270deg); }
}

@keyframes shopify-dash { 
  0% { stroke-dashoffset: 280; }
  50% { stroke-dashoffset: 75; transform: rotate(135deg); }
  100% { stroke-dashoffset: 280; transform: rotate(450deg); }
}

@keyframes acceleratedCheckoutLoadingSkeleton { 
  50% { opacity: var(--shopify-accelerated-checkout-skeleton-animation-opacity-start, 1); }
  75% { opacity: var(--shopify-accelerated-checkout-skeleton-animation-opacity-end, .5); }
  100% { opacity: var(--shopify-accelerated-checkout-skeleton-animation-opacity-start, 1); }
}

@keyframes animateIconInline { 
  0% { opacity: 1; transform: translate(0px); }
  50% { opacity: 0; transform: translate(100%); }
  51% { opacity: 0; transform: translate(-100%); }
  100% { opacity: 1; transform: translate(0px); }
}

@keyframes animateIconBlock { 
  0% { opacity: 1; transform: translateY(0px); }
  50% { opacity: 0; transform: translateY(100%); }
  51% { opacity: 0; transform: translateY(-100%); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes animateCircularProgress { 
  0% { stroke-dashoffset: var(--stroke-dasharray); }
  100% { stroke-dashoffset: 0; }
}

@keyframes ping { 
  0% { transform: scale(1); }
  100% { transform: scale(0.8); }
}

@keyframes routing-slideInFromRight-Wrk17 { 
  0% { transform: translateX(100%); opacity: 1; }
  100% { transform: translateX(0%); opacity: 1; }
}

@keyframes routing-slideOutToLeft-zPFYS { 
  0% { transform: translateX(0%); opacity: 1; }
  100% { transform: translateX(-100%); opacity: 1; }
}

@keyframes routing-slideInFromLeft-FTVeV { 
  0% { transform: translateX(-100%); opacity: 1; }
  100% { transform: translateX(0%); opacity: 1; }
}

@keyframes routing-slideOutToRight-L03hn { 
  0% { transform: translateX(0%); opacity: 1; }
  100% { transform: translateX(100%); opacity: 1; }
}

@keyframes routing-slideOverFromRight-XWQTp { 
  0% { transform: translateX(100%); opacity: 1; box-shadow: rgba(0, 0, 0, 0) -4px 0px 8px; }
  100% { transform: translateX(0%); opacity: 1; box-shadow: rgba(0, 0, 0, 0.1) -4px 0px 8px; }
}

@keyframes routing-slideOutOverRight-BqAO9 { 
  0% { transform: translateX(0%); opacity: 1; box-shadow: rgba(0, 0, 0, 0.1) -4px 0px 8px; }
  100% { transform: translateX(100%); opacity: 1; box-shadow: rgba(0, 0, 0, 0) -4px 0px 8px; }
}

@keyframes ProgressBar-animateEmpty-w1eHC { 
  0% { width: var(--kl-local-progress-min); }
  100% { width: clamp(
      var(--kl-local-progress-min),
      var(--kl-local-progress-bar-progress),
      100%
    ); }
}

@keyframes TypingIndicator-shimmer-move-SlVTW { 
  0% { background-position: right top; -webkit-text-fill-color: transparent; }
  100% { background-position: left top; -webkit-text-fill-color: transparent; }
}

@keyframes Drawer-expandToPanel-hyOTE { 
  0% { top: var(--closed-top); bottom: var(--closed-bottom); width: var(--closed-size); border-radius: var(--atlas-widget-starting-radius); }
  100% { top: var(--open-top); bottom: var(--open-bottom); width: var(--panel-width); border-radius: var(--atlas-drawer-inset-border-radius, 12px); }
}

@keyframes Drawer-collapseToWidget-v5v0n { 
  0% { top: var(--open-top); bottom: var(--open-bottom); width: var(--panel-width); border-radius: var(--atlas-drawer-inset-border-radius, 12px); opacity: 1; }
  90% { opacity: 1; background-color: var(--atlas-widget-background-color); }
  100% { top: var(--closed-top); bottom: var(--closed-bottom); width: var(--closed-size); border-radius: var(--atlas-widget-starting-radius); opacity: 0; }
}

@keyframes AnimatedHubWidget-widthBounce-jRJcf { 
  0% { width: var(--kl-local-starting-width); height: var(--kl-local-starting-height); }
  70% { width: calc(var(--kl-local-ending-width) + var(--kl-local-bounce-width)); height: var(--kl-local-ending-height); }
  100% { width: var(--kl-local-ending-width); height: var(--kl-local-ending-height); }
}

@keyframes AnimatedHubWidget-widthRetractBounce-GCvto { 
  0% { width: var(--kl-local-starting-width); height: var(--kl-local-starting-height); }
  30% { width: calc(var(--kl-local-starting-width) + var(--kl-local-bounce-width)); height: var(--kl-local-starting-height); }
  100% { width: var(--kl-local-ending-width); height: var(--kl-local-ending-height); }
}

@keyframes AnimatedHubWidget-fadeIn-rFSQ7 { 
  0% { opacity: 0; }
  70% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes AnimatedHubWidget-fadeOut-VBOi5 { 
  0% { opacity: 1; }
  30% { opacity: 0; }
  100% { opacity: 0; }
}

@keyframes HubLauncherButton-alertExpand-k9Chp { 
  0% { max-height: 0px; padding-top: 0px; padding-bottom: 0px; border-width: 0px; transform: translateY(30px); }
  70% { max-height: 60px; padding-top: var(--atlas-space-8); padding-bottom: var(--atlas-space-8); border-width: 1px; transform: translateY(-1px); }
  100% { max-height: 60px; padding-top: var(--atlas-space-8); padding-bottom: var(--atlas-space-8); border-width: 1px; transform: translateY(0px); }
}

@keyframes HubLauncherButton-alertCollapse-DijsP { 
  0% { max-height: 60px; padding-top: var(--atlas-space-8); padding-bottom: var(--atlas-space-8); border-width: 1px; transform: translateY(0px); }
  25% { max-height: 60px; padding-top: var(--atlas-space-8); padding-bottom: var(--atlas-space-8); border-width: 1px; transform: translateY(1px); }
  100% { max-height: 0px; padding-top: 0px; padding-bottom: 0px; border-width: 0px; transform: translateY(30px); }
}

@keyframes HubLauncherButton-contentFadeIn-xiUTd { 
  0% { opacity: 0; transform: scale(0.9); }
  70% { opacity: 1; transform: scale(1.015); }
  100% { opacity: 1; transform: scale(1); }
}

@keyframes HubLauncherButton-contentFadeOut-LyLTn { 
  0% { opacity: 1; transform: scale(1); }
  25% { opacity: 1; transform: scale(0.99); }
  100% { opacity: 0; transform: scale(0.9); }
}

@keyframes HubLauncherButton-oldFavoritesSlide-rB97g { 
  0% { margin-left: 0px; }
  70% { margin-left: 72px; }
  100% { margin-left: 70px; }
}

@keyframes HubLauncherButton-newFavoriteGrow-tdfxs { 
  0% { transform: scale(0.7); opacity: 0; }
  70% { transform: scale(1.05); opacity: 1; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes HubLauncher-bounceLeft-Ss6kQ { 
  100% { transform: translateX(-0.02px); }
}

@keyframes HubLauncher-bounceRight-iWzoq { 
  100% { transform: translateX(0.02px); }
}

@keyframes HubLauncher-bounceBottomLeft-Ltwkk { 
  100% { transform: translate(-0.02px, 0.02px); }
}

@keyframes HubLauncher-bounceBottomRight-xEccb { 
  100% { transform: translate(0.02px, 0.02px); }
}

@keyframes klaviyo-fadein { 
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes klaviyo-fadeout { 
  0% { opacity: 1; }
  100% { opacity: 0; }
}

@keyframes klaviyo-slideinleft { 
  0% { transform: translate3d(-100%, 0px, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideinright { 
  0% { transform: translate3d(100%, 0px, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideinup { 
  0% { transform: translate3d(0px, -100%, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideindown { 
  0% { transform: translate3d(0px, 100%, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-fadeinup { 
  0% { opacity: 0; transform: translate3d(0px, 10%, 0px); visibility: visible; }
  100% { opacity: 1; transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideintopleft { 
  0% { transform: translate3d(-100%, -100%, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideintopright { 
  0% { transform: translate3d(100%, -100%, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideinbottomright { 
  0% { transform: translate3d(100%, 100%, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-slideinbottomleft { 
  0% { transform: translate3d(-100%, 100%, 0px); visibility: visible; }
  100% { transform: translate3d(0px, 0px, 0px); }
}

@keyframes klaviyo-spinner { 
  100% { transform: rotate(360deg); }
}

@keyframes klaviyo-flash { 
  0%, 50%, 100% { opacity: 1; }
  25%, 75% { opacity: 0; }
}

@keyframes klaviyo-heartbeat { 
  0% { transform: scale(1); }
  14% { transform: scale(1.3); }
  28% { transform: scale(1); }
  42% { transform: scale(1.3); }
  70% { transform: scale(1); }
}

@keyframes klaviyo-pulse { 
  0% { transform: scale3d(1, 1, 1); }
  50% { transform: scale3d(1.1, 1.1, 1.1); }
  100% { transform: scale3d(1, 1, 1); }
}

@keyframes klaviyo-flipTop { 
  0% { transform: rotateX(0deg); z-index: 2; }
  0%, 99% { opacity: 0.99; }
  100% { transform: rotateX(-90deg); opacity: 0; }
}

@keyframes klaviyo-flipBottom { 
  0%, 50% { z-index: -1; transform: rotateX(90deg); opacity: 0; }
  51% { opacity: 0.99; }
  100% { opacity: 0.99; transform: rotateX(0deg); z-index: 5; }
}

@keyframes kl_reviews__list_loading__spinner { 
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

@keyframes fadein { 
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@-webkit-keyframes ci-bounce { 
  0%, 20%, 50%, 80%, 100% { transform: translateY(0px); }
  40% { transform: translateY(-30px); }
  60% { transform: translateY(-20px); }
}

@keyframes ci-bounce { 
  0%, 20%, 50%, 80%, 100% { }
  40% { transform: translateY(-30px); }
  60% { transform: translateY(-20px); }
}

@keyframes gp-marquee-scroll { 
  0% { transform: translateX(0px); }
  100% { transform: translateX(-100%); }
}

@keyframes sceFade { 
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes sceIn { 
  0% { opacity: 0; transform: scale(0.92) translateY(16px); }
  100% { opacity: 1; transform: scale(1) translateY(0px); }
}

@keyframes sceShake { 
  0%, 100% { transform: translateX(0px); }
  20% { transform: translateX(-6px) rotate(-3deg); }
  40% { transform: translateX(6px) rotate(3deg); }
  60% { transform: translateX(-4px) rotate(-2deg); }
  80% { transform: translateX(3px) rotate(1deg); }
}

@keyframes scePulse { 
  0%, 100% { box-shadow: rgba(255, 255, 255, 0.3) 0px 0px 0px 0px; }
  50% { box-shadow: rgba(255, 255, 255, 0) 0px 0px 0px 12px; }
}

@keyframes sceSpin { 
  100% { transform: rotate(360deg); }
}

@keyframes sceConfettiPop { 
  0% { opacity: 1; transform: translate(0px, 0px) rotate(0deg) scale(1); }
  100% { opacity: 0; transform: translate(var(--cx),var(--cy)) rotate(720deg) scale(.2); }
}

